import { expectDiagnostics } from "@typespec/compiler/testing";
import { describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";

// a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_writes
describe("@writes", () => {
  // T015_01: @writes([TaskRow]) inside @component Agent, TaskRow inside @component Store in @dependsOn — zero diagnostics
  // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_writes
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T015.T015_01
  it("T015_01: @writes store model in @dependsOn — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      namespace Components {
        @component(#{
          type: ComponentType.Store,
        })
        namespace TaskStore {
          model TaskRow { id: string; }
        }

        @component(#{
          type: ComponentType.Agent,
        })
        @dependsOn([Components.TaskStore])
        namespace ReviewAgent {
          @tool(#{ sequential: false })
          @writes([Components.TaskStore.TaskRow])
          op create_task(): void;
        }
      }
    `);
  });

  // T015_02: @writes on model — TypeSpec extern dec rejects model target
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T015.T015_02
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_writes:Products.A10nBlueprintEngine.Features.OperationCallGraph.writes_op_only:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_component:Products.A10nBlueprintEngine.Features.OperationCallGraph.writes_op_only:must
  it("T015_02: @writes on model — TypeSpec extern dec rejects non-operation target", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      namespace Components {
        @component(#{
          type: ComponentType.Store,
        })
        namespace TaskStore {
          model TaskRow { id: string; }
        }

        @component(#{
          type: ComponentType.Agent,
        })
        @dependsOn([Components.TaskStore])
        namespace ReviewAgent {
          @writes([Components.TaskStore.TaskRow])
          model WriteResult { id: string; }
        }
      }
    `);
    expectDiagnostics(diagnostics, {
      code: "decorator-wrong-target",
    });
  });

  // T015_03: @writes([PayloadModel]) where PayloadModel is inside non-Store component — writes-invalid-target
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T015.T015_03
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_writes:Products.A10nBlueprintEngine.Features.OperationCallGraph.writes_target_store:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_component:Products.A10nBlueprintEngine.Features.OperationCallGraph.writes_target_store:must
  it("T015_03: @writes model inside non-Store component — writes-invalid-target", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      namespace Components {
        @component(#{
          type: ComponentType.Service,
        })
        namespace MyApiService {
          model PayloadModel { data: string; }
        }

        @component(#{
          type: ComponentType.Agent,
        })
        @dependsOn([Components.MyApiService])
        namespace ReviewAgent {
          @tool(#{ sequential: false })
          @writes([Components.MyApiService.PayloadModel])
          op create_task(): void;
        }
      }
    `);
    expectDiagnostics(diagnostics, {
      code: "@a10n/blueprint-typespec/writes-invalid-target",
      message: /PayloadModel/,
    });
  });

  // T015_04: @writes(["TaskRow"]) string literal — TypeSpec rejects non-model arg
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T015.T015_04
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_writes:Products.A10nBlueprintEngine.Features.OperationCallGraph.targets_typed:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_component:Products.A10nBlueprintEngine.Features.OperationCallGraph.targets_typed:must
  it("T015_04: @writes with string literal — TypeSpec rejects invalid-argument", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      @component(#{
        type: ComponentType.Agent,
      })
      namespace Components.MyAgent {
        @tool(#{ sequential: false })
        @writes(["TaskRow"])
        op create_task(): void;
      }
    `);
    expectDiagnostics(diagnostics, [
      { code: "invalid-argument" },
    ]);
  });

  // T015_06: @tool(#{ sequential: false }) op with no @writes — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T015.T015_06
  it("T015_06: @tool(#{ sequential: false }) op with no @writes — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{
        type: ComponentType.Agent,
      })
      namespace Components.ReviewAgent {
        @tool(#{ sequential: false })
        op create_task(): void;
      }
    `);
  });

  // T015_07: @writes multiple store models in @dependsOn — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T015.T015_07
  it("T015_07: @writes multiple store models in @dependsOn — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      namespace Components {
        @component(#{
          type: ComponentType.Store,
        })
        namespace TaskStore {
          model TaskRow { id: string; }
          model ProjectRow { id: string; name: string; }
        }

        @component(#{
          type: ComponentType.Agent,
        })
        @dependsOn([Components.TaskStore])
        namespace ReviewAgent {
          @tool(#{ sequential: false })
          @writes([Components.TaskStore.TaskRow, Components.TaskStore.ProjectRow])
          op batch_write(): void;
        }
      }
    `);
  });

  // T015_11: action op inside @uiRoute namespace carries @writes([StoreRow]) — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T015.T015_11
  it("T015_11: @writes in @uiRoute action op with @dependsOn — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      namespace Components {
        @component(#{
          type: ComponentType.Store,
        })
        namespace TaskStore {
          model TaskRow { id: string; title: string; }
        }

        @component(#{
          type: ComponentType.Ui,
        })
        @dependsOn([Components.TaskStore])
        namespace MyUi {
          @uiRoute(#{ path: "/tasks" })
          namespace TaskListRoute {
            @writes([Components.TaskStore.TaskRow])
            op on_create_task(): void;
          }
        }
      }
    `);
  });

  // T015_08: @reads and @writes coexist on the same op — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T015.T015_08
  it("T015_08: @reads and @writes coexist on same op — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      namespace Components {
        @component(#{
          type: ComponentType.Store,
        })
        namespace TaskStore {
          model TaskRow { id: string; status: string; }
        }

        @component(#{
          type: ComponentType.Agent,
        })
        @dependsOn([Components.TaskStore])
        namespace ReviewAgent {
          @tool(#{ sequential: false })
          @reads([Components.TaskStore.TaskRow])
          @writes([Components.TaskStore.TaskRow])
          op update_task(): void;
        }
      }
    `);
  });
});
